## Task: task-007
Implement: C:\Users\ogace\CodexManager\CodexManager\src\Hooks\UseCopy.ts

### What To Do
Add error handling to the clipboard API call so failures are reflected in the UI rather than silently swallowed.

### Exact Change
Line 9, current code:
```ts
navigator.clipboard.writeText(Text);
```

Change to:
```ts
navigator.clipboard.writeText(Text).catch(() => SetCopied(false));
```

**Why:** `navigator.clipboard.writeText` returns a Promise. Currently it's fire-and-forget, so if the clipboard write fails (e.g., permissions denied, unfocused window), the UI still shows "Copied!" which is misleading. The `.catch` resets `Copied` to false so the success indicator is not shown on failure.

### Full Current File
```ts
import { useState, useCallback, useRef } from "react";

export function UseCopy(TimeoutMs = 1500): [boolean, (Text: string) => void] {
  const [Copied, SetCopied] = useState(false);
  const TimerRef = useRef<ReturnType<typeof setTimeout>>(undefined);

  const Copy = useCallback(
    (Text: string) => {
      navigator.clipboard.writeText(Text);
      SetCopied(true);
      if (TimerRef.current) clearTimeout(TimerRef.current);
      TimerRef.current = setTimeout(() => SetCopied(false), TimeoutMs);
    },
    [TimeoutMs]
  );

  return [Copied, Copy];
}
```

