    SetToast({ Message, Type });
    if (Type === "Error") console.error("[Toast]", Message);
    clearTimeout(ToastTimer.current);
    ToastTimer.current = setTimeout(() => SetToast(null), Type === "Error" ? 8000 : 3000);
  }, []);
```

